-- Migration 012b_fix: Fix implementation plans batch B — insert missing draft_legislation_notes
BEGIN;
-- ID 13
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    13,
    'The NLC distributes ~R3 billion annually in grants but has been systematically compromised by political capture, irregular allocations, and outright fraud under the Mampane-era board. The SIU and Hawks investigations (2020–2024) established a clear evidentiary basis for prosecution and institutional redesign. The overhaul proceeds on three parallel tracks: (1) completing criminal accountability through the Hawks/NPA, (2) reconstituting the board under a competence-based appointment framework, and (3) enacting the Lottery Amendment Bill to mandate competitive grant-making, mandatory audits, and ring-fenced beneficiary categories. Operation Vulindlela and the DPSA provide cross-cutting support on board appointment processes. Success is measured by a clean NLC audit opinion within three years and an independently verified grant allocation rate above 95% to qualifying civil-society organisations.',
    '[{"step":1,"description":"The Minister of Trade, Industry and Competition formally requests that the SIU submit its proclamation report to the NPA for prosecution decisions; simultaneously, the Minister terminates any remaining irregular board appointments and appoints an interim administrator with a 90-day mandate to stabilise grant disbursements and freeze irregular commitments","timeline":"Q1–Q2 2025","responsible_party":"DTIC Minister / SIU / NPA Hawks"},{"step":2,"description":"Parliament passes the Lottery Amendment Bill: key provisions include competitive grant-making processes with published criteria, mandatory independent audit of every grant above R500,000, a 24-month moratorium on politically affiliated organisations receiving grants, and a ring-fenced 40% allocation to registered NPOs in health, education, and disaster relief","timeline":"Q2–Q3 2025","responsible_party":"DTIC / Portfolio Committee on Trade, Industry and Competition / Parliament"},{"step":3,"description":"Reconstitute the NLC board: the DPSA-led technical assessment panel (as per Operation Vulindlela board appointment norms) screens nominees for financial management competence, civil-society expertise, and conflict-of-interest declarations; Minister appoints an eight-member board with staggered terms; all nominees publicly disclosed before appointment","timeline":"Q3 2025","responsible_party":"DTIC Minister / DPSA / Portfolio Committee"},{"step":4,"description":"New board commissions a full forensic audit of all NLC grants allocated between 2018 and 2024; audit conducted by an Auditor-General-approved auditing firm; findings published on the NLC website within 90 days of completion; referrals to NPA for any additional criminal conduct identified","timeline":"Q4 2025–Q2 2026","responsible_party":"NLC Board / Auditor-General SA / NPA"},{"step":5,"description":"Implement a digitised grant management system: end-to-end online application, assessment scoring, approval workflow, and disbursement tracking integrated with the National Treasury Vulekamali portal; all NLC grant decisions published in a public register within 30 days of approval","timeline":"Q4 2025–Q3 2026","responsible_party":"NLC / SITA / National Treasury"},{"step":6,"description":"Three-year NLC performance compact with DTIC: annual targets for grant disbursement rate, beneficiary compliance audits, cost-to-serve ratio (admin costs below 8% of distributions), and audit outcomes; compact tabled before Portfolio Committee annually","timeline":"From Q1 2026 annually","responsible_party":"DTIC / NLC Board / Auditor-General SA"}]',
    '2025–2028: Amendment Act passed by Q3 2025; board reconstituted Q3 2025; forensic audit completed Q2 2026; clean audit by FY2027/28',
    'Forensic audit: ~R15 million (AGSA procurement). Digital grant management system: ~R40 million (SITA/DTIC capital budget). Board and operational restructuring: absorbed within NLC operational budget (~R180 million/year admin allocation).',
    'Lotteries Amendment Bill (currently before Parliament); potential consequential amendments to the Lotteries Act 57 of 1997 (Section 10 board appointment criteria and Section 26 grant allocation procedures); no new primary legislation required beyond the Amendment Bill.',
    '',
    'The Amendment Bill was introduced by DTIC in 2023 and has cross-party support in the Portfolio Committee following extensive media coverage of the SIU findings. The DA, ANC reformist faction, and ActionSA have all publicly endorsed stronger oversight. The main procedural risk is delays in parliamentary scheduling given a congested legislative programme. GNU dynamics favour passage: both the ANC and DA have strong incentives to demonstrate accountability credentials ahead of the 2026 local elections.',
    'The UK National Lottery Community Fund publishes full grant registers with beneficiary names, amounts, and outcomes — the transparency model SA should replicate. Australia''s Australian Sports Foundation faced similar governance failures in 2019 and implemented an independent board appointment panel with competency matrices, leading to a clean audit within two years. The Irish National Lottery regulatory model (Commission for Regulation of Utilities oversight) provides a template for independent statutory oversight of lottery proceeds.'
);

-- ID 14
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    14,
    'The Public Procurement Act (Act 28 of 2024) consolidates the PPPFA and provides a legislative platform for extending the designation and localisation system across national, provincial, and municipal procurement. SA currently designates 22 product categories; the target is 35% of government spend by value supporting locally produced goods by 2030. The critical implementation gaps are inconsistent compliance monitoring, weak verification of local content claims (fraud in set-top-box and clothing categories was documented by SARS/ITAC), and poor integration with SARS trade data for enforcement. DTIC leads through the B-BBEE Commission and ITAC; National Treasury''s Office of the Chief Procurement Officer (OCPO) is the enforcement anchor. Operation Vulindlela has identified procurement reform as a Tier 1 intervention.',
    '[{"step":1,"description":"National Treasury OCPO publishes the Public Procurement Act implementation regulations under Sections 16 and 17 covering designation criteria, local content verification methodology, and the supplier database integration requirements; gazette for 60-day comment, drawing on ITAC''s existing local content verification protocols","timeline":"Q2–Q4 2025","responsible_party":"National Treasury OCPO / DTIC / ITAC"},{"step":2,"description":"Expand designated product list from 22 to at least 35 categories by 2026: priority additions include pharmaceutical APIs, EV components, agricultural equipment, and renewable energy balance-of-plant items; ITAC conducts economic impact assessments for each new category before designation is gazetted","timeline":"Q3 2025–Q4 2026","responsible_party":"DTIC / ITAC / SARS Trade Statistics"},{"step":3,"description":"Deploy the Local Content Verification System (LCVS): an integrated platform linking supplier self-declarations to SARS import/export data and CIPC manufacturing certificates; flag anomalies for ITAC investigation; integrate with the Central Supplier Database (CSD) administered by National Treasury","timeline":"Q4 2025–Q2 2026","responsible_party":"National Treasury OCPO / SARS / ITAC / SITA"},{"step":4,"description":"Establish a localisation compliance inspectorate within ITAC: 40 dedicated verification officers with authority to conduct factory audits, review production records, and refer fraudulent local content claims to the NPA; publish quarterly compliance reports","timeline":"Q1–Q3 2026","responsible_party":"ITAC / DTIC / NPA"},{"step":5,"description":"Provincial and municipal capability building: National Treasury leads a structured programme to train 2,000 procurement officials in designation compliance across all nine provinces and the 257 municipalities; embed a localisation compliance checklist in the OCPO e-procurement platform (SAGE/Transversal)","timeline":"Q2 2026–Q4 2027","responsible_party":"National Treasury OCPO / COGTA / Provincial Treasuries"},{"step":6,"description":"Annual localisation performance report: DTIC publishes a consolidated report tracking designated-category spend as a share of total government procurement, compliance rates by department, local content verification outcomes, and employment impact estimates; tabled before Cabinet and the Portfolio Committee on Trade, Industry and Competition","timeline":"Annual from Q2 2026","responsible_party":"DTIC / National Treasury OCPO / Stats SA"}]',
    '2025–2030: Regulations gazetted Q4 2025; LCVS operational Q2 2026; expanded designation list by Q4 2026; 35% localisation target by 2030',
    'Local Content Verification System: ~R80 million (SITA capital project). ITAC inspectorate: ~R45 million/year (additional personnel). Training programme: ~R30 million over two years. Total incremental cost ~R200 million over five years; offset by estimated R2–4 billion/year reduction in procurement leakages and import substitution.',
    'Public Procurement Act 28 of 2024 (primary enabling legislation, enacted). Implementing regulations required under Sections 16, 17, and 24. No further primary legislation needed. Amended ITAC Act regulations may be required to formalise ITAC''s local content verification mandate.',
    '',
    'Section 217 of the Constitution permits preferential procurement policies, providing constitutional cover. The Public Procurement Act was passed with broad GNU support. DTIC and National Treasury alignment is strong under Operation Vulindlela. The main political risk is resistance from large multinational suppliers and some DA-governed municipalities that prioritise price over localisation. COSATU and SAFTU strongly support localisation as a job-creation mechanism, providing organised labour backing.',
    'Brazil''s Regime Diferenciado de Contratações (RDC) uses mandatory local content verification linked to the Receita Federal tax database — the model for SA''s LCVS integration with SARS. India''s Public Procurement (Preference to Make in India) Order (2017) expanded designated categories to 60+ items with a tiered local content requirement (50–60%) and has been credited with driving 12–15% import substitution in government spend. Indonesia''s Tingkat Komponen Dalam Negeri (TKDN) system uses factory audits and digital certificates — comparable to the ITAC inspectorate model.'
);

-- ID 15
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    15,
    'The EEIP allows multinationals that structurally cannot sell equity — due to JSE listing rules, global parent ownership requirements, or sector restrictions — to fulfil B-BBEE ownership obligations through ring-fenced investments in SA operations, skills, enterprise and supplier development, or socioeconomic development. The DTI B-BBEE Commission approved the first EEIP in 2016 (Microsoft); by 2024, approximately 18 EEIPs had been approved with committed values exceeding R50 billion. The expansion programme targets 40 approved EEIPs by 2028, with total committed investment of R150 billion, by streamlining the approval process, reducing approval timelines from 18 months to 6 months, and extending EEIP eligibility to new sectors (fintech, healthcare, agro-processing). The B-BBEE Commission, DTIC, and the relevant sector councils are the key institutional actors.',
    '[{"step":1,"description":"B-BBEE Commission and DTIC conduct a regulatory review of the EEIP Guidelines (issued under Section 13 of the B-BBEE Act): reduce approval timeline target from 18 to 6 months by introducing a pre-application consultation stage, standardised term sheet templates, and a dedicated EEIP fast-track desk within the Commission","timeline":"Q1–Q3 2025","responsible_party":"B-BBEE Commission / DTIC"},{"step":2,"description":"Publish revised EEIP sector guidelines for five new priority sectors: fintech/digital payments, private healthcare, pharmaceutical manufacturing, agro-processing, and renewable energy; each guideline specifies eligible investment categories, minimum quantum thresholds, and measurement methodology aligned to the relevant B-BBEE Sector Codes","timeline":"Q3 2025–Q2 2026","responsible_party":"DTIC / B-BBEE Commission / Sector Councils (e.g., FSCA for fintech, SAHPRA for pharma)"},{"step":3,"description":"DTIC Invest SA unit establishes a dedicated EEIP investor relations desk: proactively identify and approach 50 qualifying multinationals with SA operations above R500 million revenue; provide pre-application advisory services, draft term sheet support, and facilitating introductions to enterprise and supplier development partners","timeline":"Q2 2025–ongoing","responsible_party":"DTIC Invest SA / B-BBEE Commission"},{"step":4,"description":"Digitise the EEIP application and monitoring portal: replace paper-based submissions with an end-to-end online system covering application, document upload, Commission review workflow, approval gazette, and annual progress reporting; integrate with CIPC and SARS for corporate and tax verification","timeline":"Q4 2025–Q2 2026","responsible_party":"B-BBEE Commission / SITA / CIPC"},{"step":5,"description":"Establish an EEIP compliance monitoring framework: B-BBEE Commission conducts annual verification of EEIP commitments against actual disbursements; publish an annual EEIP scorecard (company-level, anonymised for commercially sensitive items); non-compliant EEIPs trigger a formal notice with 90-day remedy period before B-BBEE level downgrade","timeline":"From Q1 2026 annually","responsible_party":"B-BBEE Commission / DTIC"},{"step":6,"description":"Cabinet-level EEIP investment summit (biennial): DTIC hosts a structured engagement with EEIP-approved and EEIP-eligible multinationals, aligned with the SA Investment Conference; target committing an additional R50 billion in EEIP investments at each summit","timeline":"Biennial from Q4 2025","responsible_party":"DTIC / Presidency / B-BBEE Commission / Invest SA"}]',
    '2025–2028: Revised guidelines Q3 2025; digital portal Q2 2026; 40 approved EEIPs by 2028; R150 billion cumulative committed investment by 2030',
    'B-BBEE Commission operational costs for dedicated EEIP desk and portal: ~R30 million (DTIC budget). SITA digital portal development: ~R25 million. Investment summit costs: ~R5 million per event. Total incremental government cost ~R70 million over five years; the investment leverage ratio is approximately 2,000:1.',
    'B-BBEE Act 53 of 2003 (as amended by Act 46 of 2013) provides the statutory basis. No new primary legislation required. EEIP Guidelines are issued by DTIC as administrative instruments under Section 13 of the B-BBEE Act and can be revised without parliamentary process. Sector Codes require B-BBEE Commission concurrence.',
    '',
    'B-BBEE reform is politically charged, but EEIP expansion enjoys unusually broad support because it attracts foreign direct investment without diluting black ownership targets — it is additive rather than substitutive. The ANC BEE lobby supports it as a mechanism for enterprise and supplier development; the DA supports it as an FDI-friendly B-BBEE pathway; business (BLSA, BUSA) advocates for it as reducing transformation compliance costs for multinationals. The main resistance comes from B-BBEE fronting hawks who worry that EEIPs become a loophole. The B-BBEE Commission''s compliance monitoring framework directly addresses this concern.',
    'Malaysia''s National Key Economic Areas (NKEAs) under the ETP allowed foreign investors to satisfy Bumiputera equity requirements through structured investment programmes in skills and supply chain development — a direct EEIP analogue, achieving ~RM200 billion in committed investments by 2016. India''s FDI sectoral conditions allow equivalent investment pathways in defence and retail where ownership limits apply. Brazil''s Lei de Informática grants tax incentives to technology companies that invest a percentage of revenue in R&D, analogous to the skills-development EEIP pathway.'
);

-- ID 16
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    16,
    'The Presidential Commission on the 4th Industrial Revolution (PC4IR, 2020) identified digital skills as a binding constraint on SA''s competitiveness and inclusive growth. The programme targets 1 million youth trained in coding, data science, AI, and digital literacy by 2030 through a multi-channel delivery model: SAYouth.mobi (work experience integration), the SA Youth Initiative Programme (SAYIP), public TVET colleges, and corporate partnerships with AWS, Microsoft, Google, and Huawei. DHET leads; the Department of Communications and Digital Technologies (DCDT) co-ordinates platform and connectivity infrastructure; DSBD supports SMME digitalisation; SETAs (particularly MICT SETA) fund learnerships. The programme must address SA''s structural digital divide: only 22% of TVET students have reliable broadband access.',
    '[{"step":1,"description":"Presidency/DHET establish the Digital Skills Delivery Coordinating Committee (DSDCC) chaired by the DG of DHET: representatives from DCDT, DSBD, MICT SETA, SAYouth.mobi, and three private sector partners (AWS, Microsoft, Google); committee publishes a Digital Skills Implementation Roadmap with annual milestones and sector-specific targets within 90 days","timeline":"Q1–Q2 2025","responsible_party":"DHET / Presidency / DCDT"},{"step":2,"description":"DHET integrates foundational digital literacy (coding, data handling, cybersecurity basics) into the National Curriculum and Assessment Policy Statement (CAPS) for Grades 10–12 across all public schools; SACE-accredited teacher training module delivered to 15,000 teachers through the 2025–2027 teacher development cycle","timeline":"Q2 2025–Q4 2027","responsible_party":"DHET (Basic Education) / SACE / DBE"},{"step":3,"description":"Scale TVET digital skills offerings: DHET funds 50 TVET colleges to establish dedicated Digital Skills Hubs with 20-seat computer labs, high-speed broadband (funded through USAF/DCDT Universal Service Fund), and MICT SETA-accredited short courses in coding (Python, JavaScript), data analytics, and cloud computing; target 200,000 TVET enrollments per year in digital skills by 2027","timeline":"Q3 2025–Q4 2027","responsible_party":"DHET / MICT SETA / DCDT / USAASA"},{"step":4,"description":"SAYouth.mobi digital skills integration: add digital skills work experience placements (minimum 20 hours) as a requirement for all SAYouth.mobi participants; partner with 500 tech SMEs and corporate partners to provide placements; AWS, Microsoft, and Google provide curriculum, cloud credits, and certification pathways at no cost to government","timeline":"Q2 2025–ongoing","responsible_party":"Presidency (SAYouth.mobi) / DSBD / DHET / Corporate Partners"},{"step":5,"description":"Launch a National Digital Skills Scholarship scheme: 10,000 bursaries per year for disadvantaged youth (household income below R350,000) to pursue three-year IT diplomas or BSc Computer Science degrees at public universities and TVET colleges; funded through the NSF (National Skills Fund) and NSFAS top-up allocation","timeline":"Q3 2025 (first cohort)","responsible_party":"DHET / NSF / NSFAS / Corporate Partners"},{"step":6,"description":"Establish the SA Digital Economy Observatory (SADEO) at a public research university: annual tracking of digital skills demand, supply, wages, and job placement rates; output feeds into the DSDCC annual review and informs MICT SETA PIVOTAL plan updates","timeline":"Q4 2025 (establishment); annual reports from Q2 2026","responsible_party":"DHET / DSI / NRF / MICT SETA"},{"step":7,"description":"Annual Presidential Digital Skills Summit: review milestones against the 1 million target; recognise top-performing TVET colleges and corporate partners; announce next-year investment commitments; publish cumulative skills production data broken down by demographic group, province, and skills category","timeline":"Annual from Q4 2025","responsible_party":"Presidency / DHET / DCDT"}]',
    '2025–2030: DSDCC established Q2 2025; TVET Digital Hubs operational Q4 2027; 500,000 trained by 2028; 1 million by 2030',
    'TVET Digital Hubs (50 colleges, infrastructure and equipment): R1.5 billion over three years (DHET capital budget + USAF contribution). NSF Digital Skills Scholarships: R500 million/year (NSF). SADEO establishment: R30 million (DSI/NRF). Corporate partners (AWS, Microsoft, Google) contribute curriculum, cloud credits, and certification at estimated R800 million equivalent over five years. Total public cost: ~R3 billion over five years.',
    'No new primary legislation required. Skills Development Act 97 of 1998 and the Higher Education Act 101 of 1997 provide the enabling framework. MICT SETA PIVOTAL plans must be revised to include the Digital Hubs programme. USAASA/USAF funding for connectivity requires DCDT ministerial direction under the Electronic Communications Act.',
    '',
    'Digital skills is one of the least politically contested areas of SA education policy — it enjoys support across all GNU parties, organised business (BUSA, BLSA), and the tech sector. The main implementation risk is inter-departmental coordination failure between DHET, DCDT, and DSBD, which the DSDCC is designed to resolve. COSATU and FEDUSA support digital upskilling as a future-of-work preparedness measure. Budget pressures on DHET''s infrastructure capital budget are the binding fiscal constraint.',
    'Rwanda''s Digital Ambassadors Programme trained 17,000 youth in digital skills by 2023 and integrated coding into the national curriculum from Grade 1 — the most ambitious African precedent. Kenya''s Ajira Digital Programme reached 250,000 young people in digital work skills by 2022 through a hub-based model directly analogous to the TVET Digital Hubs proposal. Estonia''s e-Estonia digital curriculum integration (from Grade 1) and ProgeTiiger coding programme are the global benchmark, with 100% of school leavers having basic coding competency.'
);

-- ID 17
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    17,
    'ITAC''s anti-dumping investigation process averages 18–36 months, far exceeding the WTO Anti-Dumping Agreement''s 12-month standard. This renders protection ineffective for industries facing acute dumping (steel, poultry, ceramics, textiles) because domestic firms often collapse before duties are imposed. The modernisation programme has three components: (1) IT system upgrade to replace ITAC''s legacy DOS-era database with a modern trade remedies management system; (2) statutory timeline amendments to the International Trade Administration Act to mandate 9-month investigation completion; and (3) an import surveillance system using SARS customs data to automatically flag potential dumping for investigation initiation. DTIC provides political oversight; National Treasury monitors revenue implications; SARS provides the data integration.',
    '[{"step":1,"description":"DTIC commissions an independent operational audit of ITAC''s anti-dumping and countervailing duty investigation process: map current workflows, identify bottlenecks (staffing, questionnaire response rates, calculation methodology disputes), and benchmark against the Australian Border Force, Brazil''s DECOM, and EU DG TRADE investigation timelines","timeline":"Q1–Q2 2025","responsible_party":"DTIC / ITAC"},{"step":2,"description":"Procure and deploy a modern Trade Remedies Case Management System (TRCMS): cloud-based platform supporting electronic questionnaire distribution, automated injury margin calculations, document management, and a public-facing case register; system must be integrated with the SARS Customs Intelligence Platform for import data feeds","timeline":"Q2 2025–Q4 2026","responsible_party":"ITAC / SITA / SARS"},{"step":3,"description":"Amend the International Trade Administration Act 71 of 2002 to: (a) mandate a maximum 9-month investigation timeline with a 3-month extension only on exceptional grounds; (b) introduce provisional anti-dumping measures within 60 days of investigation initiation where injury is prima facie; (c) establish an ITAC Import Surveillance Unit with statutory authority to initiate investigations ex officio on SARS data signals","timeline":"Q2–Q4 2025 (amendment); Q1 2026 (assent)","responsible_party":"DTIC / ITAC / Portfolio Committee on Trade, Industry and Competition"},{"step":4,"description":"Establish the Import Surveillance Unit (ISU) within ITAC: 15 dedicated analysts with access to real-time SARS Customs Intelligent Gateway (CIG) data; automated price-comparison algorithms flag import prices below 90% of normal value for any designated product; ISU initiates formal investigation within 30 days of a confirmed signal","timeline":"Q3 2025–Q2 2026","responsible_party":"ITAC / SARS / DTIC"},{"step":5,"description":"Capacity building: ITAC recruits and trains 20 additional trade remedy investigators (economists, lawyers, trade specialists); partner with the WTO Technical Assistance programme and the South African Institute of International Affairs (SAIIA) for specialised training; benchmark salaries against competition authorities to reduce staff attrition","timeline":"Q2 2025–Q4 2026","responsible_party":"ITAC / DTIC / WTO / SAIIA"},{"step":6,"description":"Annual ITAC Trade Remedies Performance Report: publish case-by-case investigation timelines, outcomes, and duty revenue collected; report to Portfolio Committee and DTIC on compliance with the 9-month statutory timeline and the ISU''s surveillance trigger performance","timeline":"Annual from Q1 2027","responsible_party":"ITAC / DTIC / Portfolio Committee"}]',
    '2025–2027: Operational audit Q2 2025; ITA Act amended Q1 2026; TRCMS deployed Q4 2026; ISU fully operational Q2 2026',
    'Trade Remedies Case Management System: ~R60 million (SITA procurement). ISU establishment (staff, infrastructure): ~R30 million/year (ITAC budget augmentation). ITA Act amendment: absorbed within DTIC legislative programme costs. Total incremental cost ~R150 million over three years; offset by estimated R500 million–R1 billion/year in additional anti-dumping duties collected and domestic industry protection value.',
    'International Trade Administration Act 71 of 2002 (amendment required for timeline mandates, provisional measure triggers, and ISU statutory authority). No treaty obligations are breached: WTO Anti-Dumping Agreement (Article 5.10) sets a 12-month recommended timeline; the proposed 9-month limit is more stringent and WTO-compliant. SARS data-sharing with ITAC requires a formal MOU under Section 70 of the Tax Administration Act.',
    '',
    'Steel and poultry industries (and their trade unions — NUMSA, FAWU) have lobbied consistently for faster anti-dumping protection; DTIC and ITAC leadership acknowledge the institutional lag. The GNU''s Operation Vulindlela has not prioritised trade remedies reform, but DTIC has significant discretion to proceed administratively. Resistance from import-dependent retail and food processing industries (who benefit from cheap imports) is the main countervailing political force. The ITA Act amendment is not politically contentious and can move quickly through Parliament.',
    'Australia''s Anti-Dumping Commission reduced average investigation duration from 22 to 8.5 months between 2013 and 2020 through case management reforms, electronic questionnaires, and provisional measure authority — the direct model for ITAC''s TRCMS. Brazil''s DECOM uses an automated import monitoring system (SISCOSERV/TEC) that generates automatic dumping alerts, directly analogous to the proposed ISU. The EU''s DG TRADE uses a nine-month default investigation timeline with mandatory provisional duties within 60 days of initiation — precisely the standard the ITA Act amendment should adopt.'
);

-- ID 23
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    23,
    'SA''s gross government debt reached approximately 75% of GDP by 2025/26, with debt service costs consuming over 22 cents of every revenue rand — the largest single line item in the national budget. National Treasury''s fiscal framework targets stabilising debt at 75–76% of GDP by 2025/26 and achieving a declining trajectory thereafter, anchored by a primary budget surplus of +0.5% of GDP. This requires a consolidated fiscal adjustment of approximately R100 billion over three years, achieved through: (1) containing the public sector wage bill below CPI plus 0.5%, (2) reducing transfers and subsidies to SOEs from R230 billion to below R100 billion over five years as SOE reforms take effect, (3) rationalising conditional grants to provinces to reduce fruitless expenditure, and (4) expanding the revenue base through improved SARS compliance and VAT gap reduction. The programme is calibrated to avoid pro-cyclical fiscal contraction while maintaining the 2026/27 primary surplus target.',
    '[{"step":1,"description":"National Treasury tables a three-year Fiscal Consolidation Framework as part of the 2025 Medium Term Budget Policy Statement (MTBPS): quantify the R100 billion adjustment requirement, itemise measures by department and entity, and commit to specific debt-to-GDP quarterly monitoring milestones reported to Parliament''s Standing Committee on Finance and Appropriations","timeline":"October 2025 MTBPS","responsible_party":"National Treasury / Minister of Finance"},{"step":2,"description":"Public sector wage bill constraint: conclude a three-year Public Service Coordinating Bargaining Council (PSCBC) wage agreement at CPI + 0.5% maximum; introduce a headcount rationalisation framework (voluntary severance packages in over-staffed functions, a moratorium on non-critical new appointments) targeting a reduction of 30,000 positions over three years through attrition","timeline":"Q1–Q3 2025 (wage negotiation); Q4 2025–Q4 2027 (headcount rationalisation)","responsible_party":"DPSA / National Treasury / PSCBC"},{"step":3,"description":"SOE fiscal exposure reduction: National Treasury implements the SOE Portfolio Management Office (PMO) framework — each SOE receiving transfers above R1 billion annually must sign a performance compact with measurable self-sufficiency milestones; Eskom equity injection programme replaced by full implementation of the debt relief/restructuring agreement conditional on generation, transmission, and distribution separation milestones","timeline":"Q1 2025 (Eskom restructuring milestones); Q3 2025 (PMO framework); ongoing","responsible_party":"National Treasury / DPME / DPE / relevant SOE boards"},{"step":4,"description":"Conditional grant rationalisation: National Treasury and COGTA review the 45 national conditional grants to provinces: consolidate overlapping grants (particularly in education infrastructure and health facility management); introduce a single performance framework with 70% expenditure and delivery targets as prerequisite for full grant disbursement; underspent grants reallocated within-year to over-performing provinces","timeline":"2025/26 Budget implementation; rationalisation completed by 2026/27 MTEF","responsible_party":"National Treasury / COGTA / Provincial Treasuries"},{"step":5,"description":"SARS compliance and revenue enhancement: implement the SARS Third-Party Data programme (auto-population of 80% of personal income tax returns by 2026), accelerate the VAT refund integrity project (reduce the R30 billion VAT refund backlog), and launch the Illicit Economy unit targeting illicit tobacco, alcohol, and fuel levies estimated at R50–80 billion in lost revenue annually","timeline":"Q1 2025–Q4 2027","responsible_party":"SARS / National Treasury"},{"step":6,"description":"Fiscal rules entrenchment: National Treasury drafts a Public Finance Management Amendment Bill to introduce a statutory debt ceiling (80% of GDP as a hard limit), a structural primary balance rule (minimum +0.5% over the business cycle), and an independent Fiscal Council to provide public assessments of budget sustainability; gazette for comment and introduce to Parliament","timeline":"Q2 2025 (draft); Q4 2026 (enactment target)","responsible_party":"National Treasury / Parliament (Finance Committees)"},{"step":7,"description":"Quarterly fiscal transparency reporting: National Treasury publishes a Fiscal Monitor (modelled on IMF practice) with real-time debt-to-GDP tracking, primary balance outturn vs. target, contingent liability register (SOE guarantees, PPP obligations), and a debt sustainability analysis update; published within 30 days of each quarter-end","timeline":"From Q2 2025 quarterly","responsible_party":"National Treasury / SARB / Stats SA"}]',
    '2025–2030: Primary surplus achieved by 2026/27; debt stabilisation by 2025/26; declining debt trajectory from 2026/27; fiscal rules legislation enacted by 2026/27',
    'Fiscal consolidation is a net revenue-positive programme. Estimated fiscal savings over five years: wage bill constraint (~R80 billion), SOE transfer reduction (~R130 billion), conditional grant efficiency (~R20 billion), SARS enhanced compliance (~R150 billion). Incremental implementation costs: PMO establishment (~R50 million), SARS Third-Party Data programme (~R200 million over two years, within SARS budget). Net fiscal improvement: R380 billion+ over five years.',
    'Public Finance Management Act 1 of 1999 (amendment for fiscal rules and debt ceiling). Money Bills Amendment Procedure and Related Matters Act for medium-term fiscal framework obligations. No constitutional amendment required (Section 216 already mandates national norms and standards for financial management). PSCBC wage agreements are binding under the Labour Relations Act and require multi-party bargaining.',
    '',
    'Fiscal consolidation is the central political fault line in GNU budget negotiations. The DA strongly supports primary surplus targets and opposes wage bill growth. The ANC faces pressure from COSATU and the public sector unions (PSA, NEHAWU, POPCRU) who resist real wage cuts and headcount rationalisation. The MK Party and EFF oppose any fiscal austerity. The GNU arithmetic gives the ANC and DA combined the votes to pass budget resolutions, but wage agreement negotiations at the PSCBC require COSATU sign-on or the risk of industrial action. The political feasibility of the fiscal rules bill is moderate — medium-term prospect if the debt trajectory stabilises and provides political cover.',
    'Chile''s structural balance fiscal rule (introduced 2001, entrenched by law in 2006) is the emerging-market benchmark: a 1% of GDP structural surplus target enforced by an independent Fiscal Advisory Council, enabling Chile to maintain investment-grade credit through commodity cycles. Ireland''s fiscal compact (post-2010 IMF programme) achieved a 14-percentage-point debt reduction over seven years through a combination of expenditure restraint and growth, without sovereign default. Kenya''s Medium Term Debt Management Strategy (2022–2025) provides an African precedent for systematic SOE contingent liability management and conditional grant rationalisation.'
);

-- ID 39
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    39,
    'The Integrated Energy Plan (IEP) is the overarching strategic framework for SA''s entire energy sector — encompassing electricity, liquid fuels, gas, and new energy vectors (hydrogen, biofuels). The 2023/24 IEP update must integrate three urgent additions absent from the 2016 IEP: (1) an LNG import pathway through Richards Bay and/or Coega for gas-to-power and industrial feedstock; (2) a green hydrogen production and export roadmap anchored by the Saldanha Bay industrial zone; and (3) coal retirement timelines consistent with IRP 2024 capacity projections and SA''s Nationally Determined Contribution (NDC) targets. The Gas Amendment Bill (currently before Parliament) is the critical enabling legislation. DMRE leads; DTIC, DFFE, and National Treasury provide cross-departmental inputs. The IEP must be gazetted no later than Q4 2025 to provide the investment certainty needed by LNG terminal developers, gas-to-power IPPs, and hydrogen project developers.',
    '[{"step":1,"description":"DMRE appoints a multidisciplinary IEP Technical Advisory Committee (TAC): energy economists, LNG specialists (from Richards Bay LNG and TotalEnergies SA), hydrogen industry representatives (HySA, SAPVIA), environmental lawyers, and civil society; TAC produces a demand scenario update (2025–2050) with explicit modelling of LNG import costs, renewable electricity growth trajectories, and industrial decarbonisation pathways","timeline":"Q1–Q2 2025","responsible_party":"DMRE / DTIC / DFFE / NBI"},{"step":2,"description":"Publish the draft IEP 2024 for public comment: 60-day comment period with regional public hearings in Gauteng, Western Cape, KwaZulu-Natal, and the Northern Cape; specific consultation sessions with the gas sector (SAOGA), mining sector (Minerals Council), and environmental groups (WWF-SA, Centre for Environmental Rights)","timeline":"Q3 2025","responsible_party":"DMRE"},{"step":3,"description":"Pass the Gas Amendment Bill: amend the Gas Act 48 of 2001 to (a) expand the definition of gas to include LNG, hydrogen, and biomethane; (b) establish a Gas Regulator function within NERSA with price oversight for piped gas and LNG imports; (c) create an open-access third-party access regime for gas transmission infrastructure; table amendments in Parliament''s Portfolio Committee on Mineral Resources and Energy","timeline":"Q2–Q4 2025","responsible_party":"DMRE / Portfolio Committee on Mineral Resources and Energy / NERSA"},{"step":4,"description":"LNG infrastructure pathway: DMRE and the dtic designate Richards Bay and Coega (Port Elizabeth) as priority LNG import terminals; issue formal Requests for Qualification (RFQ) to private terminal developers for FSRU-based LNG import facilities; NERSA establishes a regulated tariff framework for LNG transmission to power plants and industrial users","timeline":"Q3 2025–Q4 2026","responsible_party":"DMRE / DTIC / Transnet / NERSA / IPP Office"},{"step":5,"description":"Green hydrogen roadmap: DTIC and DMRE publish the SA Hydrogen Society Roadmap implementation plan with investment targets (R100 billion by 2030), priority export corridors (Germany, Netherlands, Japan), and enabling infrastructure (Saldanha Bay H2 hub, Boegoebaai deep-water port); link hydrogen production targets to renewable energy procurement under REIPPPP","timeline":"Q2 2025–Q2 2026","responsible_party":"DTIC / DMRE / DFFE / HySA / DSI"},{"step":6,"description":"Coal transition alignment: IEP incorporates a just energy transition coal retirement schedule consistent with IRP 2024 decommissioning timelines, the Presidential Climate Commission''s fair share analysis, and the JET-IP financing commitments; publish a Coalfields Economic Diversification Plan for Mpumalanga and the Free State coalfields in partnership with COGTA and affected municipalities","timeline":"Q4 2025–Q2 2026","responsible_party":"DMRE / Presidential Climate Commission / COGTA / JET-IP Secretariat"},{"step":7,"description":"Gazette final IEP 2024: published in the Government Gazette following Cabinet Economic Cluster approval; includes a binding implementation matrix with departmental responsibilities, investment triggers, and a 5-year review mechanism; tabled before Parliament''s Portfolio Committee","timeline":"Q4 2025","responsible_party":"DMRE / Cabinet Economic Cluster / Minister of Mineral Resources and Energy"}]',
    '2025–2026: TAC established Q2 2025; Gas Amendment Bill enacted Q4 2025; IEP gazetted Q4 2025; LNG RFQ issued Q4 2026; hydrogen roadmap published Q2 2026',
    'DMRE IEP process costs (TAC, modelling, public participation): ~R25 million. Gas Amendment Bill legislative process: absorbed within DMRE budget. LNG terminal development: R8–15 billion per terminal (private sector investment). Green hydrogen Saldanha Bay hub: R50–80 billion over a decade (private sector plus JET-IP). Coal transition modelling and coalfields plan: ~R20 million. Total public sector cost ~R50 million; infrastructure investment is predominantly private.',
    'Gas Act 48 of 2001 (amendment via Gas Amendment Bill — currently before Parliament). Electricity Regulation Act 4 of 2006 (Section 34 determination for gas-to-power procurement). National Environmental Management Act (NEMA) for LNG terminal and hydrogen hub EIAs. Mineral and Petroleum Resources Development Act (MPRDA) for gas exploration licensing linked to LNG import decisions.',
    '',
    'The Gas Amendment Bill faces opposition from Eskom and NUM (concerned about stranded coal assets and gas-fired power displacing coal jobs) but has strong support from DTIC, major industrials (SASOL, ArcelorMittal, Sappi), and the IPP developer community. LNG imports are politically uncontroversial as an energy security measure. Green hydrogen enjoys broad GNU support as an export opportunity. Coal retirement timelines are the most politically sensitive element — ANC members from coal-producing constituencies (Mpumalanga) and NUM resist accelerated decommissioning. The JET-IP financing framework and the Coalfields Diversification Plan are essential political accompaniments.',
    'Mozambique''s LNG development (TotalEnergies Mozambique LNG) provides a regional precedent for FSRU-based import infrastructure. Japan''s Strategic Energy Plan (6th edition, 2021) integrates hydrogen, LNG, and renewables within a single overarching framework comparable to the IEP update. Germany''s Hydrogen Action Plan and its LNG import terminal programme (launched 2022 following the Russia-Ukraine war) demonstrate rapid FSRU deployment (Deutsche ReGas at Brunsbüttel: six months from FID to first gas) — the timeline model for SA''s Richards Bay FSRU.'
);

-- ID 50
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    50,
    'NSFAS funds approximately 500,000 university students and 440,000 TVET college students annually, at a total cost exceeding R50 billion per year. The system faces R9 billion in unfunded liabilities, a near-zero loan recovery rate (less than 5% of historical loan book recovered), and mounting evidence of fraud and administrative dysfunction under successive boards. The Heher Commission (2017) recommended an income-contingent loan (ICL) system for middle-income students (quintiles 3–4) with means-tested grants retained for the poorest (quintiles 1–2). The sustainable funding model combines: (1) universal grants for quintiles 1–2 (below R350,000 household income), (2) income-contingent loans for quintiles 3–4 (R350,000–R600,000), and (3) a private-sector bursary co-investment scheme. DHET leads; National Treasury provides actuarial costing and fiscal envelope; SARS administers ICL repayments through payroll. Implementation requires the NSFAS Act amendment and the Higher Education Amendment Bill.',
    '[{"step":1,"description":"DHET commissions a comprehensive actuarial study of the NSFAS loan book and forward fiscal liability: quantify the recovery rate gap, model ICL repayment flows under alternative income thresholds and repayment rates, and produce a 20-year fiscal sustainability projection under three scenarios (grant-only, hybrid ICL, full ICL); study conducted by an actuarial firm appointed through competitive tender","timeline":"Q1–Q2 2025","responsible_party":"DHET / National Treasury"},{"step":2,"description":"Publish the Higher Education Funding Review for public comment: drawing on the actuarial study, the Heher Commission recommendations, and international ICL benchmarks (Australia HECS-HELP, England Student Finance, Germany Bafög); convene national consultations with SRC bodies, ASAUDIT, Universities South Africa (USAf), and COSATU Youth","timeline":"Q3 2025","responsible_party":"DHET / DHET Advisory Committee on Student Funding"},{"step":3,"description":"Draft and introduce the NSFAS Amendment Bill: key provisions — (a) two-tier eligibility: means-tested grants (quintiles 1–2) vs. ICL (quintiles 3–4); (b) ICL repayment triggered at income threshold of R30,000/month, at 8% of income above threshold, administered by SARS through payroll deduction; (c) independent NSFAS Board appointment process with actuarial and financial management expertise requirements; (d) quarterly NSFAS financial statements published publicly","timeline":"Q4 2025–Q2 2026","responsible_party":"DHET / National Treasury / SARS / Parliament"},{"step":4,"description":"SARS ICL repayment administration: SARS integrates ICL repayment into the PAYE payroll deduction system; develop an employer API for ICL balance and deduction rate lookup; pilot with 200 large employers before national rollout; SARS publishes annual ICL recovery statistics","timeline":"Q3 2025–Q4 2026","responsible_party":"SARS / DHET / National Treasury"},{"step":5,"description":"NSFAS administrative reform: appoint a new NSFAS Board under the revised appointment criteria; procure an enterprise resource planning (ERP) system to replace the dysfunctional legacy student loan management system; integrate with DHET''s Central Application Service (CAS) and the DHA biometric student identity verification system to eliminate ghost student fraud","timeline":"Q2 2025–Q4 2026","responsible_party":"DHET / NSFAS Board / SITA / DHA"},{"step":6,"description":"Private sector bursary co-investment scheme: DSBD and DHET launch a matched-funding scheme — for every R1 of private sector bursary above a R10 million threshold, government provides R0.50 in NSF co-funding; B-BBEE recognition at Level 2 for qualifying contributions; target R5 billion/year in private sector bursary co-investment by 2028","timeline":"Q3 2026–ongoing","responsible_party":"DHET / DSBD / B-BBEE Commission / NSF"},{"step":7,"description":"Annual NSFAS sustainability report: DHET and National Treasury publish a joint report tracking grant disbursement rates, ICL uptake, repayment recovery rate, actuarial reserve adequacy, and fraud detection outcomes; tabled before the Portfolio Committee on Higher Education and the Standing Committee on Finance","timeline":"Annual from Q1 2027","responsible_party":"DHET / National Treasury / NSFAS Board / Auditor-General SA"}]',
    '2025–2028: Actuarial study Q2 2025; NSFAS Amendment Bill enacted Q2 2026; SARS ICL system operational Q4 2026; new ERP system Q4 2026; R5 billion private bursary target by 2028',
    'Actuarial study: R5 million (DHET budget). SARS ICL system integration: R150 million (SARS capital, partly offset by long-term recovery revenue). NSFAS ERP system: R400 million over three years. Ongoing grant programme: ~R45 billion/year (existing allocation). ICL system is fiscally self-improving: modelled ICL recovery at R3–5 billion/year by 2030 (initially modest, growing to R15 billion+ by 2040 as first cohort reaches peak earnings).',
    'NSFAS Act 56 of 1999 (amendment required for two-tier eligibility, ICL provisions, and board appointment reform). Higher Education Act 101 of 1997 (consequential amendment for funding framework integration). Tax Administration Act 28 of 2011 (SARS authority to administer ICL repayments through PAYE — requires Section 179 amendment or DHET/SARS MOU under Section 70).',
    '',
    'Student funding is one of the most politically explosive issues in SA. The #FeesMustFall movement and SASCO strongly oppose any shift from grants to loans, framing it as commodification of education. The ANC''s 2023 National Conference resolution supported free education for the poor while acknowledging the need for sustainability — providing political cover for the two-tier model. The DA supports means-testing and ICL as fiscally responsible. The main political risk is student protests triggered by the ICL introduction for quintile 3–4 students. The communication strategy must emphasise that quintile 1–2 students (the majority) are unaffected and that ICL repayments are income-contingent — no repayment below R30,000/month.',
    'Australia''s HECS-HELP system (introduced 1989) is the global benchmark: income-contingent loans repaid through the tax system at 1–10% of income above the threshold; 95% recovery rate on historical loan book; zero institutional distress. England''s Student Finance system (post-2012) combines income-contingent loans with means-tested maintenance grants — the direct hybrid model SA should adopt. Germany''s Bafög provides grants plus subsidised loans with a 50% grant conversion mechanism based on academic progress — relevant to SA''s academic progression requirements.'
);

-- ID 51
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    51,
    'SA faces a critical shortage of 40,000+ artisans across electrical, plumbing, welding, pipefitting, millwrighting, boilermaking, and construction trades — a binding constraint on infrastructure delivery, private sector capital projects, and municipal service maintenance. TVET colleges produce approximately 15,000 artisan graduates per year against a demand of 30,000+. The National Technical Certificate (NTC) pass rate hovers around 60%; the Recognition of Prior Learning (ARPL) system certifies fewer than 5,000 artisans per year. The artisan pipeline programme addresses four simultaneous failures: weak industry partnerships, poor TVET lecturer quality, inadequate workshop equipment, and a slow ARPL system. DHET leads through the TVET Branch; the relevant SETAs (CHIETA, EWSETA, MERSETA, CETA) fund learnerships; the Quality Council for Trades and Occupations (QCTO) maintains qualification standards; Eskom, Transnet, and the major construction groups are key industry partners.',
    '[{"step":1,"description":"DHET and QCTO commission a National Artisan Skills Audit: map the supply-demand gap by trade category, province, and economic sector; identify the 20 critical trades with the highest shortage-to-vacancy ratios; use Rand Mutual Assurance, COID data, and industry association surveys as inputs; publish findings as the basis for targeted TVET investment prioritisation","timeline":"Q1–Q2 2025","responsible_party":"DHET / QCTO / Stats SA / Industry Associations"},{"step":2,"description":"DHET launches a Capital Equipment Recapitalisation Programme: R3 billion over three years to upgrade workshops at 50 priority TVET colleges with CNC machinery, PLC programmable systems, hydraulics and pneumatics rigs, and electrical simulation equipment aligned to current industry standards; procurement through DHET''s TVET Infrastructure Development Grant; colleges prioritised based on geographic artisan shortage data","timeline":"Q2 2025–Q4 2027","responsible_party":"DHET / TVET Infrastructure Branch / National Treasury"},{"step":3,"description":"Industry-College Partnership (ICP) model: DHET mandates that all 50 TVET colleges in artisan priority trades establish formal ICPs with at least three industry partners each; partners provide: (a) work-integrated learning (WIL) placements for N4–N6 students, (b) lecturer exchanges (industry professionals teach part-time), and (c) equipment donations counted as BBBEE enterprise development contributions; MERSETA and CHIETA provide SETA learnership co-funding for ICP participants","timeline":"Q3 2025–Q4 2026","responsible_party":"DHET / MERSETA / CHIETA / EWSETA / CETA / Industry (Eskom, Transnet, Murray & Roberts, Aveng)"},{"step":4,"description":"Lecturer quality improvement: DHET and QCTO introduce a mandatory trade test for all new TVET artisan lecturers (current practice allows unqualified appointments); establish a TVET Artisan Lecturer Bursary (100 bursaries/year) for qualified artisans to complete the PGCE in Technical Education; pay a 15% artisan lecturer allowance to attract qualified tradespeople into teaching","timeline":"Q2 2025–Q4 2026","responsible_party":"DHET / QCTO / SACE / NSF"},{"step":5,"description":"ARPL acceleration programme: QCTO and DHET invest in 30 additional ARPL assessment centres (targeting rural and peri-urban areas with high concentrations of informally skilled workers — Mpumalanga, Limpopo, Eastern Cape); digitise the trade test booking system (currently paper-based); set a target of 20,000 ARPL certifications per year by 2028 through additional assessor training and assessment centre capacity","timeline":"Q3 2025–Q4 2027","responsible_party":"QCTO / DHET / MERSETA / Industry Assessment Bodies"},{"step":6,"description":"NTC quality improvement: introduce a standardised national NTC marking and moderation framework under QCTO oversight; establish an NTC Improvement Fund (R200 million/year from NSF) for supplementary tutoring, textbooks, and online practice platforms; publish college-level NTC pass rates annually to drive accountability and informed learner choice","timeline":"Q3 2025–Q4 2026","responsible_party":"QCTO / DHET / NSF"},{"step":7,"description":"Annual Artisan Pipeline Report: DHET publishes a trade-by-trade supply-demand tracker, TVET NTC pass rates by college and trade, ARPL certification numbers, and ICP placement statistics; tabled before the Portfolio Committee on Higher Education; feeds into the SETA PIVOTAL plan update cycle","timeline":"Annual from Q1 2026","responsible_party":"DHET / QCTO / Stats SA / Portfolio Committee"}]',
    '2025–2028: Skills Audit Q2 2025; equipment recapitalisation 2025–2027; ICPs established Q4 2026; ARPL 20,000/year target by 2028; NTC pass rate target 75% by 2028',
    'Capital Equipment Recapitalisation: R3 billion over three years (DHET TVET Infrastructure Grant + NSF). ARPL assessment centre expansion: R300 million over two years. Lecturer Bursary programme: R50 million/year (DHET). NTC Improvement Fund: R200 million/year (NSF). Total public cost: ~R4.5 billion over three years. SETAs (MERSETA, CHIETA, EWSETA, CETA) contribute an additional estimated R1.5 billion in learnership co-funding through existing PIVOTAL plans.',
    'Skills Development Act 97 of 1998 (amendment to ARPL provisions enabling digital trade test booking and remote assessment). Continuing Education and Training Act 16 of 2006 (TVET quality framework provisions — amendment may be needed for mandatory lecturer trade test). QCTO Act 26A of 2008 (no amendment required; QCTO has existing authority to set occupational qualifications and assessment standards).',
    '',
    'Artisan training enjoys strong cross-party support: the DA, ANC, and EFF all publicly prioritise artisan skills as a job-creation mechanism. COSATU affiliates (NUM, NUMSA) strongly support ARPL expansion as a path to formal certification for their members. The construction sector (SAFCEC, MBSA) and engineering sector (SEIFSA, CESA) have lobbied for TVET-industry partnerships for years. The main implementation risk is DHET''s historically weak capacity to execute capital infrastructure projects on time — the recapitalisation programme requires dedicated project management capacity (potentially through the Infrastructure Fund).',
    'Germany''s dual apprenticeship system (Duales Ausbildungssystem) is the global benchmark: 1.3 million apprentices per year, 80% employer co-funding, 95% employment rate post-apprenticeship. Switzerland''s VET system achieves 70% of school leavers entering vocational training with industry-designed curricula. Singapore''s Institute of Technical Education (ITE) achieved a transformation from a low-status system to 90% employment rate post-graduation through mandatory industry advisory committees for each trade programme — directly applicable to SA''s ICP model. Australia''s Australian Apprenticeships system uses a TAFE-industry dual delivery model with government wage subsidies comparable to SA''s SETA learnership grants.'
);

-- ID 52
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    52,
    'SA''s 21 Sector Education and Training Authorities (SETAs) collect the 1% Skills Development Levy (SDL) on payroll — generating R17–18 billion per year. Of this, 80% is retained by SETAs (20% goes to the NSF): 20 percentage points are disbursed as mandatory grants (returned to employers without verified skill delivery), 49.5 percentage points fund discretionary grants and learnerships, and 10.5 percentage points cover SETA administration costs. Independent evaluations (DPME, SETA Landscape Review 2020) found that the majority of mandatory grant recipients do not implement meaningful training; SETA administration costs are excessive; and the 21-SETA landscape fragments scarce sector expertise. The SETA Landscape Review recommends consolidation to 9–12 SETAs with clearer sector mandates, mandatory outcome verification for all grants, and a shift from input-based to outcome-based funding. DHET leads the reform; the DPSA, National Treasury, and NEDLAC are key stakeholders.',
    '[{"step":1,"description":"DHET publishes the SETA Consolidation White Paper: drawing on the 2020 Landscape Review and a new commissioned SETA performance audit (by DPME), the White Paper proposes the 9–12 SETA configuration with revised sector mandates, merger timelines, and transitional arrangements for staff, assets, and accreditation; published for public comment through NEDLAC for 90 days","timeline":"Q2–Q4 2025","responsible_party":"DHET / DPME / NEDLAC"},{"step":2,"description":"Amend the Skills Development Act 97 of 1998: key amendments — (a) reduce SETAs from 21 to 12 by 2027, specifying the merged configurations by Schedule; (b) replace mandatory grants (currently 20% of SDL returned without verification) with outcome-based training grants requiring QCTO-verified completion; (c) cap SETA administration costs at 8% of SDL receipts (current average 10.5%); (d) introduce a SETA Performance Scorecard assessed annually by DHET","timeline":"Q1–Q3 2026","responsible_party":"DHET / Portfolio Committee on Higher Education and Training / Parliament"},{"step":3,"description":"SETA merger process: DHET appoints merger facilitators for each of the 9 merger clusters; each merged SETA publishes a Business Integration Plan within six months covering: governance structure, staff integration (labour law compliant), IT system consolidation, accreditation continuity for QCTO-registered providers, and the sector skills plan update","timeline":"Q4 2025–Q4 2027","responsible_party":"DHET / SETA Boards / DPSA / QCTO"},{"step":4,"description":"Replace mandatory grants with outcomes-based training grants: DHET and QCTO design the Verified Training Outcomes Grant (VTOG) framework — employers claim grants only upon submitting QCTO-verified completion records or SAQA-endorsed assessment results; introduce a digital grant claim system integrated with SARS payroll data to prevent double-claiming; pilot with three SETAs in 2026/27 before national rollout","timeline":"Q2 2026–Q2 2027 (pilot); Q3 2027 (national)","responsible_party":"DHET / QCTO / SARS / SETA Boards"},{"step":5,"description":"Strengthen the NSF strategic allocation: the 20% of SDL flowing to the NSF (R3.5 billion/year) is currently fragmented across 300+ discretionary projects with weak impact measurement; DHET establishes an NSF Investment Committee with published investment criteria, competitive project selection, and mandatory independent impact evaluations for all NSF grants above R10 million","timeline":"Q2 2025–Q4 2026","responsible_party":"DHET / NSF / DPME / National Treasury"},{"step":6,"description":"SETA Performance Scorecard implementation: DHET publishes annual SETA scorecards rating each SETA on: (a) SDL-to-training conversion ratio, (b) QCTO qualification completions per R1 million of levy, (c) learner employment rate 12 months post-training, (d) administration cost ratio, and (e) employer satisfaction index; bottom-quartile SETAs placed under DHET administration review","timeline":"Annual from Q1 2027","responsible_party":"DHET / DPME / Auditor-General SA"},{"step":7,"description":"NEDLAC tripartite review: government, business (BUSA), and organised labour (COSATU, FEDUSA, NACTU) conduct a three-yearly strategic review of the SDL rate, SETA configuration, and outcome metrics; first review targets 2028 to assess post-merger performance and determine whether the SDL rate should be maintained, reduced, or differentiated by sector","timeline":"Triennial from 2028","responsible_party":"NEDLAC / DHET / National Treasury / BUSA / COSATU"}]',
    '2025–2028: White Paper Q4 2025; Skills Development Act amended Q3 2026; SETA mergers completed Q4 2027; VTOG national rollout Q3 2027; NSF Investment Committee Q4 2026',
    'SETA consolidation generates administrative savings of R400–600 million/year (reduction from 10.5% to 8% administration ratio). Outcome-based grants redirect R3–4 billion/year (the current mandatory grant pool) toward verified training. DHET''s reform process costs: ~R80 million for the performance audit, White Paper consultations, and merger facilitation. VTOG digital system: ~R120 million (SITA/SARS integration). NSF Investment Committee: absorbed within NSF operational budget. Net long-term fiscal efficiency gain: R500 million–R1 billion/year in improved SDL utilisation.',
    'Skills Development Act 97 of 1998 (amendment required for SETA consolidation, mandatory grant replacement, and administration cap). Skills Development Levies Act 9 of 1999 (consequential amendment if levy rate or distribution ratios change). No constitutional amendment required. QCTO Act 26A of 2008 (potential amendment to formalise VTOG verification role).',
    '',
    'SETA reform is one of the most contested areas of SA skills policy. Organised labour (COSATU, FEDUSA, NACTU) strongly oppose SETA consolidation, viewing SETAs as important tripartite governance spaces and resisting any reduction in labour influence. Business (BUSA, BLSA) strongly support mandatory grant reform and consolidation. The ANC''s 2023 National Conference resolution supported "a comprehensive review of the SETA landscape" — providing political cover for consolidation. The NEDLAC process is critical for labour buy-in. The reform should be framed as improving skill delivery outcomes rather than reducing labour''s role — retaining tripartite governance in the consolidated SETAs is essential for political feasibility.',
    'Ireland''s SOLAS (Skills and Labour Market Research Unit) consolidated 33 vocational training organisations into a single national body in 2013, achieving a 30% reduction in administrative costs while increasing training output by 15% within three years. Singapore''s SkillsFuture system shifted from input-based (course attendance) to outcome-based (skills certification and employment) funding, tripling the return on training investment measured by wage premium. Germany''s BIBB (Federal Institute for Vocational Education and Training) provides the tripartite sector skills planning model SA should replicate in the consolidated SETA governance framework.'
);

-- ID 98
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    98,
    'The Expanded Public Works Programme (EPWP) has created over 14 million work opportunities since its 2004 launch but averages only 32 days of employment per participant — insufficient for meaningful skills acquisition or economic independence. The EPWP Phase 4 (2019–2024) budget of R77 billion achieved its volume targets but failed to address the programme''s structural flaw: participants exit with no recognised qualification, no pathway to formal employment, and no enterprise development support. A reformed EPWP would function as a National Skills Pathway: automatic linkage of all EPWP participants to TVET qualifications via DHET, SETA learnerships via the LMTF, and enterprise development support via SEDA — transforming temporary employment into durable human capital. DPWI would retain programme coordination; DHET, DSBD, and the NSF would co-fund the skills and enterprise components.',
    '[
      {"step":1,"title":"EPWP Skills Pathway Framework Design","description":"Establish an inter-departmental EPWP Reform Task Team (DPWI, DHET, DSBD, NSF, LMTF) to design the National Skills Pathway model. Map all existing EPWP work categories (infrastructure, environment, social, non-state) to relevant TVET qualifications and SETA learnership frameworks. Define a minimum 60-day EPWP participation threshold to trigger automatic skills pathway enrolment.","timeline":"Months 1–6","responsible_party":"DPWI / DHET / DSBD / NSF"},
      {"step":2,"title":"TVET College Integration Programme","description":"Pilot EPWP-TVET integration in 20 TVET colleges across all nine provinces. EPWP participants in infrastructure and environment sectors enrol in relevant NQF Level 2–4 qualifications (construction, civil engineering, agriculture) with Recognition of Prior Learning (RPL) credits for EPWP work experience. DHET funds the TVET placements from the NSF.","timeline":"Months 6–18 (pilot); Months 18–36 (scale)","responsible_party":"DHET / TVET Colleges / DPWI"},
      {"step":3,"title":"SETA Learnership Pathway Integration","description":"Negotiate MOUs between DPWI and all relevant SETAs (CETA for construction, EWSETA for environment, LGSETA for social sector) to automatically enrol eligible EPWP graduates in NQF Level 3–5 learnerships. Employer levy credits available to public bodies employing EPWP graduates as learners. Target: 50,000 learnership enrolments per year by Year 3.","timeline":"Months 12–30","responsible_party":"DPWI / SETAs / LMTF / DHET"},
      {"step":4,"title":"SEDA Enterprise Development Integration","description":"Establish EPWP Enterprise Development Hubs co-located with SEDA regional offices. All EPWP participants assessed for enterprise development potential during induction. SEDA provides business plan development, SEFA microloan access, and incubation support for viable enterprise ideas. Target: 20,000 EPWP-linked enterprise registrations per year.","timeline":"Months 12–36","responsible_party":"DSBD / SEDA / SEFA / DPWI"},
      {"step":5,"title":"Minimum Duration and Quality Standards Reform","description":"Revise EPWP reporting metrics: move from ''work opportunities created'' to ''skills-linked work opportunities'' as the primary KPI. Introduce a minimum 60-day employment standard for all EPWP projects (currently averaging 32 days). Require all EPWP implementing agents to provide RPL documentation and pathway referrals as a condition of public body incentive grant payment.","timeline":"Months 6–18","responsible_party":"DPWI / National Treasury / Implementing Agents"},
      {"step":6,"title":"EPWP Digital Participant Tracking System","description":"Develop a unified EPWP Participant Tracking System linked to the national Learner Management System (LMS) administered by DHET and the LMTF. Track each participant from EPWP entry through TVET/learnership/enterprise development outcomes. Enable DPWI to report longitudinal exit outcomes (employment, qualification attainment, business registration) to Parliament.","timeline":"Months 6–24","responsible_party":"DPWI / DHET / SITA / NSF"},
      {"step":7,"title":"EPWP Phase 5 Design with Skills Pathway Mandate","description":"Incorporate the National Skills Pathway model into EPWP Phase 5 (2024–2029) policy framework. Require all national and provincial EPWP implementing departments to allocate a minimum 15% of EPWP budget to the skills and enterprise pathway components. Table Phase 5 framework in Parliament with revised EPWP Act (or Ministerial Policy Directive under existing DORA framework) to give skills pathway obligations legal force.","timeline":"Months 18–36","responsible_party":"DPWI / Cabinet Economic Cluster / Parliament"}
    ]',
    '6 months for framework design; 18 months for pilot at 20 TVET colleges; 36 months for full national rollout; Phase 5 framework by 2026',
    'Additional R3–5 billion per year over current EPWP allocation for TVET integration, SETA learnerships, and SEDA enterprise hubs. NSF has capacity to co-fund from levy surpluses (NSF balance exceeded R10 billion in 2023). Total EPWP Phase 5 budget requirement: R80–90 billion over 5 years (up from R77 billion in Phase 4).',
    'No new primary legislation strictly required — EPWP operates under DORA allocations and Ministerial policy directives. An amendment to the Skills Development Act 97 of 1998 would entrench the EPWP-SETA learnership linkage. A Ministerial Policy Direction from DPWI under the Public Service Act can mandate skills pathway compliance for all national implementing departments.',
    '',
    'DPWI Minister can issue the reformed EPWP framework as a policy directive — no Cabinet vote required for the operational model. DHET co-operation is essential and is likely given NSF overfunding and TVET college capacity constraints. The GNU labour partners (COSATU) support expanded EPWP but will demand quality employment conditions. ANC and DA both support EPWP expansion in principle; the skills reform framing avoids ideological conflict.',
    'Ethiopia''s Productive Safety Net Programme (PSNP) successfully integrated public works with skills development and livelihood support, reducing chronic food insecurity. India''s MGNREGA (National Rural Employment Guarantee Act) is the largest public works programme globally and has been progressively linked to skill development through PMKVY (Pradhan Mantri Kaushal Vikas Yojana). Brazil''s Bolsa Família combined with PRONATEC skills programme shows complementary social protection and skills pathway design.'
);

-- ID 99
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    99,
    'South Africa''s public infrastructure delivery is characterised by endemic cost overruns, schedule delays, contractor failures, and poor value for money — collectively estimated to destroy R20–40 billion in value annually. The Infrastructure Delivery Management System (IDMS) was introduced by DPWI in 2010 as a national framework for uniform infrastructure planning, procurement, and delivery — but adoption has been inconsistent across national and provincial departments. Reform entails three binding interventions: mandatory Project Management Offices (PMOs) for all projects above R100 million, CIDB-certification of Infrastructure Delivery Agents (IDAs), and a National Infrastructure Project Portal tracking 500+ projects in real time. These reforms address the structural capacity deficit identified by the Presidential Infrastructure Coordinating Commission (PICC) and the Construction Industry Development Board (CIDB).',
    '[
      {"step":1,"title":"IDMS Compliance Audit and Gap Analysis","description":"Commission a national IDMS compliance audit across all national and provincial departments managing infrastructure budgets above R500 million per year. Assess PMO establishment, use of Construction Procurement Strategy, CIDB contractor grading compliance, and reporting to the PICC/DPWI. Publish audit results and ranking of departments by IDMS compliance score.","timeline":"Months 1–6","responsible_party":"DPWI / CIDB / National Treasury PPP Unit"},
      {"step":2,"title":"Mandatory PMO Establishment for R100m+ Projects","description":"Issue a National Treasury Instruction Note mandating that all infrastructure projects with total project cost above R100 million must be managed through a formally constituted Project Management Office (PMO), staffed by SACPCMP-registered Construction Project Managers and ECSA-registered Engineers at key roles. PMOs report project schedule, cost, and quality status monthly to DPWI''s Chief Infrastructure Delivery Officer.","timeline":"Months 6–18","responsible_party":"National Treasury / DPWI / SACPCMP / ECSA"},
      {"step":3,"title":"Infrastructure Delivery Agent Certification","description":"Establish a CIDB accreditation framework for Infrastructure Delivery Agents (IDAs): entities mandated by departments to implement infrastructure projects on their behalf (DBSA, COEGA, IDC, provincial IDAs). Certification requirements: proven PMO capacity, clean audit history, IDMS compliance record. Decertified IDAs cannot be appointed for new projects — a key lever for consequence management.","timeline":"Months 12–24","responsible_party":"CIDB / DPWI / National Treasury"},
      {"step":4,"title":"National Infrastructure Project Portal","description":"Develop and launch a real-time National Infrastructure Project Portal under the Office of the President/PICC, tracking all public infrastructure projects above R50 million. Portal publishes: project name, budget, actual expenditure, planned vs. actual completion, contractor identity, and project manager. Open-data API for civil society and media access. Built on existing DPWI PMIS system with SITA support.","timeline":"Months 12–30","responsible_party":"DPWI / Presidency/PICC / SITA / National Treasury"},
      {"step":5,"title":"Construction Contractor Development and Grading Reform","description":"Reform CIDB contractor grading to require demonstrated project management capacity (not just financial capacity) for grades 7–9. Introduce a Contractor Development Programme for grades 4–6 emerging contractors to build PMO skills. Partner with CETA for site management and project administration learnerships for emerging contractor staff.","timeline":"Months 18–36","responsible_party":"CIDB / CETA / DPWI"},
      {"step":6,"title":"Consequence Management for Project Failures","description":"Introduce a framework for infrastructure project failure consequence management: where projects exceed budget by more than 20% or schedule by more than 12 months without force majeure justification, an automatic AGSA-triggered investigation is conducted. Implementing officials face PFMA Section 38 proceedings. Contractors are listed on a National Infrastructure Poor Performers Register and barred from new public contracts for 2–5 years.","timeline":"Months 12–24","responsible_party":"DPWI / National Treasury / AGSA / SIU"},
      {"step":7,"title":"Annual IDMS State of Infrastructure Delivery Report","description":"Table an annual State of Infrastructure Delivery Report to Parliament from DPWI, covering: total infrastructure expenditure and performance against plan, cost and schedule variance by department, consequence management outcomes, and CIDB contractor grading statistics. Table the report alongside the National Budget cycle for integrated fiscal oversight.","timeline":"Annual from Year 2","responsible_party":"DPWI Chief Infrastructure Delivery Officer / Portfolio Committee on Public Works"}
    ]',
    '6 months for audit; 18 months for PMO mandate and portal launch; 36 months for full CIDB IDA certification system; ongoing annual reporting',
    'National Infrastructure Project Portal: R150–200 million (IT development and hosting). PMO compliance monitoring: R80 million/year operational. CIDB certification system: R50 million. Expected savings from reduced cost overruns: R5–10 billion/year (conservative estimate against R20–40 billion annual value destruction baseline).',
    'No new primary legislation required. IDMS is a DPWI policy framework; its binding application can be enforced through National Treasury Instruction Notes under the PFMA. CIDB Act 38 of 2000 provides the legal basis for contractor and IDA accreditation. A Presidential PICC Instruction can mandate project portal reporting across all spheres of government.',
    '',
    'IDMS reform has technical consensus across National Treasury, DPWI, and CIDB. The construction industry (MBSA, ASAQS, SAICE) actively supports professionalisation of the public client. Political resistance comes from departments that resist external oversight of their procurement. The PICC''s mandate from the Presidency provides the inter-governmental authority to enforce compliance. The GNU''s infrastructure-led growth agenda in the 2024 Government Programme of Action provides political cover.',
    'Singapore''s Building and Construction Authority (BCA) is the benchmark for public project management professionalisation in a small open economy. UK''s Infrastructure and Projects Authority (IPA) provides the Government Major Projects Portfolio model directly applicable to SA. Australia''s Department of Infrastructure publishes a Major Infrastructure Tracker directly analogous to the proposed National Infrastructure Project Portal. New Zealand''s Treasury Gateway Review system provides an independent project assurance model worth replicating.'
);

-- ID 100
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    100,
    'South Africa''s public infrastructure faces an estimated R70 billion maintenance backlog across schools, hospitals, courts, and government offices — the result of decades of maintenance budgets being raided to cover operational spending shortfalls. The Built Environment Professional Associations of South Africa (BPESA) estimate that R1 in timely preventive maintenance prevents R5 in capital replacement costs, making the maintenance backlog one of the most capital-inefficient features of South Africa''s public finances. A PFMA amendment to ring-fence maintenance budgets as protected expenditure — alongside a standardised government asset maintenance accounting standard and AO-level accountability for maintenance compliance — is the minimum institutional reform required to arrest infrastructure decay. The National Treasury''s 2023 Medium-Term Expenditure Framework identified maintenance underspending as a systemic fiscal risk.',
    '[
      {"step":1,"title":"Maintenance Backlog Quantification","description":"Commission a national maintenance backlog audit across schools (DBE), hospitals (NDoH), courts (DoJ), prisons (DCS), and government offices (DPWI/PMTE). Use the SACPCMP and ASAQS condition assessment methodology. Quantify the backlog by department, asset class, and province. Establish a baseline for the Maintenance Backlog Register.","timeline":"Months 1–12","responsible_party":"DPWI / National Treasury / DBE / NDoH / DoJ"},
      {"step":2,"title":"PFMA Amendment: Ring-fenced Maintenance Budgets","description":"Draft and table a PFMA Amendment Bill adding a new Section 38A: Accounting Officers of departments with immovable assets above a threshold must appropriate a minimum maintenance allocation (proposed: 2.5% of asset replacement value per year, consistent with international benchmarks). Maintenance allocations may not be reprogrammed to operational spending without written National Treasury approval and tabling in Parliament.","timeline":"Months 6–24 (legislative cycle)","responsible_party":"National Treasury / DPWI / Parliament Portfolio Committee on Finance"},
      {"step":3,"title":"Asset Maintenance Accounting Standard","description":"Develop a Government Maintenance Accounting Standard in consultation with the Accounting Standards Board (ASB) and the South African Institute of Chartered Accountants (SAICA). The standard requires all national departments to disclose: maintenance budget, actual maintenance expenditure, deferred maintenance liability, and condition rating of major asset classes — in their annual financial statements.","timeline":"Months 12–24","responsible_party":"National Treasury / ASB / DPWI"},
      {"step":4,"title":"Maintenance Delivery Units in Key Departments","description":"Establish dedicated Maintenance Delivery Units (MDUs) in DPWI (for government offices), DBE (schools), NDoH (hospitals), and DoJ (courts). MDUs managed by SACPCMP-registered Facilities Managers. MDUs responsible for planning, contracting, and monitoring maintenance programmes. CIDB contractor grading used for maintenance contractor procurement.","timeline":"Months 12–30","responsible_party":"DPWI / DBE / NDoH / DoJ / DPSA"},
      {"step":5,"title":"Maintenance Backlog Clearance Programme","description":"Design a 10-year Maintenance Backlog Clearance Programme funded from a combination of ring-fenced maintenance budgets, Presidential Infrastructure Coordinating Commission priority allocations, and conditional grants to provinces. Prioritise schools and clinics in rural provinces (Eastern Cape, Limpopo, KwaZulu-Natal) where backlog density is highest. Target: clear 50% of critical condition assets within 5 years.","timeline":"Months 18–36 for programme design; 10-year execution","responsible_party":"DPWI / National Treasury / Provincial Works Departments / DBE / NDoH"},
      {"step":6,"title":"AO Accountability for Maintenance Compliance","description":"Link DG/HoD performance agreements to maintenance budget compliance. Where Accounting Officers reprogramme maintenance funds without NT approval, invoke PFMA Section 38 financial misconduct proceedings. AGSA to include maintenance underspending as a material irregularity category in annual audit reports.","timeline":"Months 6–18","responsible_party":"DPSA / National Treasury / AGSA"},
      {"step":7,"title":"Annual Maintenance State of Infrastructure Report","description":"Table an annual Maintenance and Asset Condition Report to Parliament, covering: maintenance expenditure vs. budget by department, backlog status, condition ratings of key asset classes, and consequence management outcomes. Joint reporting by DPWI and National Treasury.","timeline":"Annual from Year 2","responsible_party":"DPWI / National Treasury / Portfolio Committee on Public Works"}
    ]',
    '12 months for backlog audit; 24 months for PFMA amendment legislative cycle; 36 months for MDU establishment; 10-year backlog clearance programme',
    'Ring-fenced maintenance budget at 2.5% of asset replacement value implies approximately R10–15 billion per year additional maintenance spending (from current ~R3 billion). Estimated long-term savings: R25–40 billion over 10 years by avoiding capital replacement of maintained assets. Backlog clearance programme: R70 billion over 10 years, funded through reprioritisation and conditional grants.',
    'Primary legislation: PFMA Amendment Bill adding Section 38A (ring-fenced maintenance appropriations). Secondary instruments: revised GRAP (Generally Recognised Accounting Practice) standards for maintenance liability disclosure; National Treasury Instruction Note on maintenance accounting. Disposal of State Land Act amendments may be needed for asset disposal linked to maintenance rationalisation.',
    '',
    'National Treasury controls the budget appropriation process — a PFMA amendment requires Treasury''s support, which is likely given NT''s own concerns about maintenance backlog fiscal risk. The ANC has historically resisted ring-fencing of budget lines as inflexible, but the scale of infrastructure decay is now politically visible (muddy school floors, broken hospital equipment). DA, IFP, and other GNU partners are likely to support PFMA maintenance protection as a governance reform.',
    'UK''s Treasury Green Book requires all government departments to maintain assets at a defined condition standard and report on deferred maintenance liability. Germany''s Bundesbau (Federal Building Administration) uses a 1.5% annual maintenance rule for federal buildings. New Zealand''s Crown Infrastructure Review mandates 2% of asset replacement value in annual maintenance appropriations. Australia''s National Schools'' Capital Investment Framework ring-fences maintenance within education capital grants.'
);

-- ID 101
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    101,
    'National Treasury''s PPP Unit has processed only 47 PPP transactions since 2000 — an average of fewer than 2 per year — against a social infrastructure deficit that requires hundreds of new schools, clinics, courts, and social housing units. Treasury Regulation 16, which governs PPPs, requires three formal Treasury Approvals (feasibility, procurement, and financial close) that together consume 24–36 months before construction can begin. This regulatory burden was designed for large complex transactions (Gautrain, hospitals) but is disproportionate for smaller social infrastructure PPPs under R500 million. Reform entails: a streamlined approval pathway for social infrastructure PPPs under R500 million; standardised output specifications and contract templates (already developed by the PPP Unit for schools and clinics); and a PPP Project Preparation Facility (PPF) capitalised at R500 million through DBSA to fund feasibility studies and transaction advisors for undercapacitated departments.',
    '[
      {"step":1,"title":"Treasury Regulation 16 Streamlined Pathway Design","description":"National Treasury PPP Unit drafts amended Treasury Regulation 16 creating a simplified approval pathway for social infrastructure PPPs with capital value under R500 million. Streamlined pathway: single Treasury Approval (combined feasibility and procurement) rather than three sequential approvals. Approval timeline target: 9 months from project registration to financial close for standard projects using template contracts.","timeline":"Months 1–9","responsible_party":"National Treasury PPP Unit / DPWI / DoJ / DBE"},
      {"step":2,"title":"Standardised PPP Contract Template Library","description":"Commission finalisation of standardised output specification documents and PPP contract templates for schools, primary healthcare clinics, courts, social housing, and small government office buildings. Templates to cover: output specifications, payment mechanisms, performance monitoring, step-in rights, and termination. Peer-reviewed by private sector (BASA, ASISA) and legal advisors. Published as open-access documents.","timeline":"Months 6–18","responsible_party":"National Treasury PPP Unit / DBSA / DPWI"},
      {"step":3,"title":"PPP Project Preparation Facility (PPF)","description":"Capitalise a PPP Project Preparation Facility at R500 million through DBSA, co-funded by National Treasury and development finance institutions (AfDB, IFC). PPF provides grants and concessional loans to undercapacitated national and provincial departments for: feasibility studies, environmental impact assessments, land surveys, and transaction advisor fees. PPF structured as a revolving fund: successful PPPs repay feasibility costs at financial close.","timeline":"Months 6–18","responsible_party":"DBSA / National Treasury / AfDB / IFC"},
      {"step":4,"title":"Social Infrastructure PPP Pipeline Development","description":"Identify and register 50 shovel-ready social infrastructure PPP projects across schools (DBE), clinics (NDoH), courts (DoJ), and social housing (DRDLR/NHFC). Priority projects: under-resourced provinces (Eastern Cape, Limpopo, Northwest). Engage private sector (construction, FM, banking) through a structured PPP market consultation. Publish a 3-year PPP pipeline on the National Treasury website.","timeline":"Months 9–24","responsible_party":"National Treasury PPP Unit / Sector Departments / DPWI"},
      {"step":5,"title":"PPP Capacity Building in Provinces","description":"Establish PPP Capacity Desks in the National Treasury offices of the three largest provinces (Gauteng, KwaZulu-Natal, Western Cape) and provide PPP transaction advisory support to the three lowest-capacity provinces (Limpopo, Northwest, Eastern Cape). Train 200 provincial officials in PPP feasibility, procurement, and contract management over 2 years, using the National Treasury PPP Manual and DBSA training programmes.","timeline":"Months 12–30","responsible_party":"National Treasury / DBSA / Provincial Treasuries"},
      {"step":6,"title":"Fast-track First 10 Social Infrastructure PPPs","description":"Select 10 pilot social infrastructure PPP projects from the pipeline to test the streamlined TR16 pathway: 4 schools, 3 clinics, 2 courts, 1 social housing project. Target financial close within 12 months of project registration under the new pathway. Document lessons learned and publish a pilot evaluation report for refinement of the streamlined framework.","timeline":"Months 18–36","responsible_party":"National Treasury PPP Unit / DBSA / Sector Departments"},
      {"step":7,"title":"PPP Performance Monitoring and Reporting","description":"Establish a mandatory PPP Performance Reporting system: all PPPs in operation must submit quarterly performance reports to the National Treasury PPP Unit covering availability payments, service delivery KPIs, and unitary charge adjustments. Annual PPP Portfolio Report tabled to Parliament''s Standing Committee on Finance. Publish open-data performance dashboard for civil society oversight.","timeline":"Months 24–36","responsible_party":"National Treasury PPP Unit / Portfolio Committee on Finance"}
    ]',
    '9 months for TR16 streamlined pathway; 18 months for PPF capitalisation and contract template library; 36 months for first 10 pilot PPPs at financial close',
    'PPP Project Preparation Facility: R500 million (DBSA/NT co-funding). PPP Unit capacity expansion: R80 million/year operational. Expected private sector investment mobilised: R15–25 billion over 5 years from 50 pipeline projects. Total government direct expenditure: R1–1.5 billion; total social infrastructure value unlocked: R20–30 billion.',
    'Primary instrument: Amendment to Treasury Regulation 16 (issued under PFMA Section 76) — no parliamentary vote required, can be issued by the Minister of Finance by notice. PPP Project Preparation Facility: DBSA Act 13 of 1997 authorises DBSA to provide project preparation finance. MFMA Section 120 governs municipal PPPs and may require parallel amendment for local government social infrastructure.',
    '',
    'The Minister of Finance can amend Treasury Regulation 16 by notice under the PFMA — no parliamentary approval needed. National Treasury has been internally reviewing TR16 since 2021. The DBSA board has repeatedly endorsed a PPP Project Preparation Facility. GNU partners broadly support social infrastructure delivery through PPPs; the ANC''s concern historically has been private profit from social services, which can be addressed through output-specification design that focuses on availability payments rather than user charges.',
    'UK''s Private Finance Initiative (PFI/PF2) delivered 700+ projects over 25 years despite well-documented efficiency concerns — the standardised contract library and HM Treasury project preparation support are directly applicable. India''s Viability Gap Funding scheme successfully mobilised private investment in social infrastructure by topping up PPP financial viability through targeted government grants. Nigeria''s InfraCredit uses partial credit guarantees to unlock PPP financing — relevant for SA''s weaker-credit provinces. Colombia''s Fourth Generation (4G) roads programme standardised PPP contracts and accelerated approvals, applicable to SA''s social infrastructure context.'
);

-- ID 102
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    102,
    'South Africa''s government owns and leases approximately 83,000 properties through the PMTE, with estimated annual energy consumption of 2,000 GWh per year — equivalent to the output of a medium-sized power station. Government buildings are among the least energy-efficient in the built environment: aging stock, poor insulation, single-glazed windows, and outdated HVAC systems. A green building mandate — requiring EDGE or Green Star SA certification for all new government buildings and a structured retrofit programme for the top 1,000 energy consumers — would reduce government energy costs by an estimated 30–40% (saving R2–3 billion per year at current Eskom tariff levels), reduce demand on the constrained national grid, and position government as a market-maker for the SA green building industry. The National Energy Efficiency Action Plan (NEEAP) and the SA National Building Regulations provide the regulatory hooks.',
    '[
      {"step":1,"title":"Government Building Energy Audit","description":"Commission energy audits of the top 2,000 government buildings by energy consumption using SANS 10400-XA compliant methodology. Establish a Government Building Energy Register under PMTE with Energy Performance Certificates (EPCs) for each audited building. Identify the top 1,000 buildings with retrofit potential (estimated energy savings above 25%).","timeline":"Months 1–18","responsible_party":"PMTE / DPWI / SANEDI / DoE"},
      {"step":2,"title":"Green Building Mandate for New Government Buildings","description":"Issue a DPWI Ministerial Directive under GIAMA Section 13 requiring all new government buildings with a gross floor area above 1,000 m² to achieve EDGE or Green Star SA 4-Star certification before occupation. Include the mandate in all PMTE lease and construction contracts. Estimated cost premium for green certification: 2–5% of construction cost, with lifecycle payback within 5 years.","timeline":"Months 6–12","responsible_party":"DPWI / PMTE / GBCSA / DoE"},
      {"step":3,"title":"Government Building Retrofit Programme","description":"Design and launch a 5-year Government Building Retrofit Programme targeting the top 1,000 energy-consuming properties. Retrofit interventions: LED lighting, solar PV rooftop installation, insulation upgrades, HVAC replacement, and smart metering. Procure through PMTE centralised procurement to achieve economies of scale. Financing: combination of PMTE maintenance budget, DBSA green bond facility, and PACE (Property Assessed Clean Energy) financing instruments.","timeline":"Months 18–60","responsible_party":"PMTE / DPWI / DBSA / SANEDI"},
      {"step":4,"title":"Solar PV on Government Rooftops","description":"Identify 500 government buildings with suitable rooftop area (>500 m²) for solar PV installation. Issue a consolidated REIPPPP-style tender for rooftop solar across all 500 buildings under a single Power Purchase Agreement structure managed by PMTE. Estimated combined capacity: 200–300 MW. Revenue/savings model: private developer installs at no capital cost to government; government pays reduced tariff under long-term PPA.","timeline":"Months 12–30","responsible_party":"PMTE / DPWI / NERSA / DoE / IPP Office"},
      {"step":5,"title":"Green Building Capacity in PMTE","description":"Establish a Green Building Technical Unit within PMTE: 15 built environment professionals (mechanical engineers, architects, energy auditors) with GBCSA or EDGE accreditation. Unit manages certification process for new buildings, oversees retrofit programme, and maintains the EPC database. Partner with CETA for built environment professional development pipeline.","timeline":"Months 6–18","responsible_party":"PMTE / DPWI / GBCSA / CETA"},
      {"step":6,"title":"Energy Performance Disclosure Requirement","description":"Implement Energy Performance Certificates (EPCs) under the National Building Regulations (NBR) for all government-occupied buildings above 2,000 m². Require annual disclosure of energy consumption per m² on the PMTE public dashboard. Buildings with EPC ratings below D must implement retrofit plans within 24 months. Disclosure creates reputational accountability for User Departments.","timeline":"Months 12–24","responsible_party":"DPWI / DTIC / DoE / SABS"},
      {"step":7,"title":"Green Government Procurement Standard","description":"Issue a National Treasury Instruction Note requiring all PMTE lease agreements for privately owned buildings to mandate minimum SANS 10400-XA energy efficiency compliance and EPC disclosure. Government to lead by example: no lease renewals above R5 million/year for buildings with EPC rating below C from 2027. This creates a demand-side signal for the private green building market.","timeline":"Months 12–24","responsible_party":"National Treasury / PMTE / DPWI"}
    ]',
    '18 months for energy audit and green building mandate; 30 months for solar PV procurement; 60 months for full top-1,000 retrofit programme',
    'Energy audit programme: R200 million. Government Building Retrofit Programme: R8–12 billion over 5 years (partially financed through DBSA green bonds and PPAs). Solar PV programme: developer-financed under PPA (zero capital to government). Expected energy cost savings: R2–3 billion/year from Year 3; cumulative 10-year savings: R25–35 billion.',
    'No new primary legislation required. GIAMA Section 13 authorises DPWI to set standards for government immovable assets. National Building Regulations and Building Standards Act 103 of 1977 (SANS 10400-XA) provides the EPC and energy efficiency compliance framework. National Energy Act 34 of 2008 and the NEEAP provide policy authority for energy efficiency mandates.',
    '',
    'DPWI Minister can issue the green building mandate under existing GIAMA powers without parliamentary approval. National Treasury''s Instruction Note on green procurement requires only the Minister of Finance''s signature. The DA (major GNU partner) has a strong green economy platform and is likely to champion this. The ANC''s Just Transition framework supports government-led green building. Eskom supports demand reduction through efficiency as it eases grid pressure.',
    'USA''s Federal Green Buildings Mandate (Executive Order 14057, 2021) requires all new federal buildings to achieve net-zero emissions by 2030 and all existing federal buildings to cut emissions 50% by 2032 — the most ambitious government green building programme globally. Australia''s NABERS (National Australian Built Environment Rating System) is a mandatory government building energy rating system directly applicable to SA. Singapore''s Green Mark programme (mandatory for all new buildings over 5,000 m²) shows a comparable developing-economy implementation. UK''s Greening Government Commitments require a 50% reduction in energy use across the government estate by 2032.'
);

-- ID 103
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    103,
    'National and provincial departments hold significant well-located urban land — Cape Town Foreshore, Franschhoek valley, Ekurhuleni industrial corridors, Tshwane CBD parcels — that is underutilised or vacant while South African cities face acute affordable housing deficits. The total affordable housing unit shortfall is estimated at 2.3 million units nationally (DHS 2023). A structured Urban Land Release Programme using Section 42 of the PFMA (disposal of state assets) and the Disposal of State Land Act 48 of 1961 would match well-located state land with qualifying developers, Social Housing Institutions (SHIs), and community land trusts — enabling 500,000+ affordable housing units on state land within 10 years. DPWI/PMTE is the custodian of national state land; provinces hold additional land through provincial public works; municipalities through MFMA Section 14 disposal processes.',
    '[
      {"step":1,"title":"Urban State Land Audit","description":"Commission a comprehensive audit of all national, provincial, and municipal land parcels within 5 km of urban economic nodes (CBDs, transport hubs, employment centres) across the 8 metros and 15 secondary cities. Map against infrastructure availability (water, sewer, roads, public transport). Classify each parcel by: ownership, zoning, current use, accessibility score, and development potential. Use GIS-enabled Land Information System (LIS) integrated with Deeds Registry data.","timeline":"Months 1–12","responsible_party":"DPWI / PMTE / DRDLR / Presidency / Metros"},
      {"step":2,"title":"Land Release Programme Framework","description":"Establish the Urban Land Release Programme (ULRP) framework under PFMA Section 42, specifying: qualifying land parcels (urban, minimum 5,000 m², accessible), qualifying recipients (SHIs registered with the Social Housing Regulatory Authority, NHFC-approved developers, community land trusts), and minimum affordable housing proportions (60% units below R600,000 or rental below R5,000/month). Framework approved by Cabinet and gazetted.","timeline":"Months 6–18","responsible_party":"DPWI / DHS / National Treasury / Presidency"},
      {"step":3,"title":"Well-located Land Disposal Instrument","description":"Develop a standardised Land Disposal Instrument: a long-term ground lease (50–99 years) rather than freehold transfer, retaining state ownership while enabling private development. Ground lease includes: affordability covenants, minimum densities (60+ units/hectare), public amenity requirements, and reversion clauses if affordability conditions are breached. This addresses ANC concerns about ''selling state land'' while enabling development.","timeline":"Months 6–18","responsible_party":"National Treasury / DPWI / DHS / SHRA"},
      {"step":4,"title":"Pilot Release: 10 Flagship Urban Land Parcels","description":"Identify and release 10 pilot urban land parcels (2 per metro in Cape Town, Johannesburg, Tshwane, eThekwini, Ekurhuleni) totalling at least 500 hectares. Run competitive developer selection processes managed by NHFC/SHRA. Require each parcel to deliver a minimum of 500 affordable units within 5 years of land transfer. Target total: 5,000+ units from pilot phase.","timeline":"Months 18–36","responsible_party":"DPWI / NHFC / SHRA / Metros"},
      {"step":5,"title":"Housing Development Finance Integration","description":"Integrate the Urban Land Release Programme with NHFC, DBSA, and the Housing Development Finance Architecture. NHFC provides construction finance and homeowner mortgage guarantees. DBSA provides bulk infrastructure finance for serviced land. FLISP subsidies apply to units priced R300,000–R600,000. Facilitate participation of private banks (BASA members) through standardised bond registration on NHFC-guaranteed units.","timeline":"Months 12–30","responsible_party":"DHS / NHFC / DBSA / BASA / National Treasury"},
      {"step":6,"title":"Planning and Zoning Acceleration","description":"Establish a National Land Release Facilitation Unit (NLRFU) within the Presidency/DPWI to fast-track rezoning, environmental authorisation, and bulk services provision for released parcels. Use Section 33 of the SPLUMA (Spatial Planning and Land Use Management Act) to issue national development directives for ULRP projects. Target: planning approvals within 12 months of land release decision (current average: 3–5 years).","timeline":"Months 12–30","responsible_party":"Presidency / DPWI / DFFE (environmental) / Metros"},
      {"step":7,"title":"10-Year Urban Land Release Target and Annual Reporting","description":"Set a binding 10-year target: 500,000 affordable housing units on released state land by 2034. Publish an annual Urban Land Release Progress Report to Parliament covering: land released (hectares), units under construction, units completed, affordability compliance, and SHI performance. Link DG performance agreements in DPWI and DHS to ULRP milestones.","timeline":"Annual from Year 2","responsible_party":"DPWI / DHS / Presidency / Portfolio Committees on Public Works and Human Settlements"}
    ]',
    '12 months for urban land audit; 18 months for framework and disposal instruments; 36 months for 10 pilot parcels at financial close; 10-year programme to 500,000 units',
    'Urban land audit: R150 million. National Land Release Facilitation Unit: R60 million/year. Land is transferred at below-market ground lease rates (estimated revenue forgone: R5–10 billion in implicit subsidy over 10 years vs. R30–50 billion in housing infrastructure investment mobilised). Net fiscal cost: R1.5–2 billion/year in programme administration and infrastructure co-investment.',
    'PFMA Section 42 governs disposal of state assets, requiring National Treasury approval and parliamentary disclosure. Disposal of State Land Act 48 of 1961 is the primary disposal authority for national land. SPLUMA Act 16 of 2013 Section 33 authorises national development directives to override municipal planning delays. Social Housing Act 16 of 2008 and the SHRA Regulations provide the social housing delivery framework. A Land Release Bill could consolidate and streamline these instruments.',
    '',
    'The PFMA Section 42 process requires National Treasury approval and notification to Parliament but not a parliamentary vote — the Minister of Finance and DPWI DG can approve individual disposals. Cabinet approval of the ULRP framework is needed for the programme architecture. The ANC-led government has repeatedly committed to well-located land release (RDP to NDP to MTSF) but has not delivered at scale. The GNU''s 2024 Government Programme of Action commits to releasing 14,000 hectares of state land for housing — the ULRP provides the implementation mechanism. Opposition parties broadly support land release for housing; the risk is municipal resistance to densification.',
    'Singapore''s Housing Development Board (HDB) has housed 80% of the population on state-owned land through 99-year ground leases — the definitive urban land release success story. Kenya''s Affordable Housing Programme (Boma Yangu) releases national and county government land to private developers via ground leases with affordability covenants. Brazil''s Minha Casa Minha Vida programme combined federal land release with construction subsidies to deliver 5 million+ units. UK''s Homes England releases public sector brownfield land to housing associations and developers — the NHFC/SHRA model in SA is directly analogous.'
);

